static uint8_t hex_char_to_nibble(char c)
{
    if (c >= '0' && c <= '9') return (uint8_t)(c - '0');
    if (c >= 'A' && c <= 'F') return (uint8_t)(c - 'A' + 10);
    if (c >= 'a' && c <= 'f') return (uint8_t)(c - 'a' + 10);
    return 0xFF;
}

static bool diag_authenticate(const char *token_str)
{
    uint8_t token_bytes[AUTH_TOKEN_LEN];
    uint32_t len = (uint32_t)strlen(token_str);

    if (len != AUTH_TOKEN_LEN * 2U) {
        return false;
    }

    for (uint32_t i = 0; i < AUTH_TOKEN_LEN; i++) {
        uint8_t hi = hex_char_to_nibble(token_str[i * 2U]);
        uint8_t lo = hex_char_to_nibble(token_str[i * 2U + 1U]);
        if (hi == 0xFF || lo == 0xFF) return false;
        token_bytes[i] = (hi << 4) | lo;
    }

    /*
     * crypto_verify_hmac_token() should verify:
     * HMAC-SHA256(device_secret, challenge || device_id || timestamp)
     * Implementation is platform-specific.
     */
    bool result = crypto_verify_hmac_token(token_bytes, AUTH_TOKEN_LEN);

    /* Constant-time clear */
    volatile uint8_t *p = token_bytes;
    for (uint32_t i = 0; i < AUTH_TOKEN_LEN; i++) {
        p[i] = 0;
    }

    return result;
}

/* ============================================================
 * Utility: Parse hex address from string
 * ============================================================ */
static bool parse_hex(const char *str, uint32_t *out)
{
    if (str == NULL || out == NULL) return false;

    /* Skip optional "0x" prefix */
    if (str[0] == '0' && (str[1] == 'x' || str[1] == 'X')) {
        str += 2;
    }

    uint32_t val = 0;
    uint32_t count = 0;
    while (*str && count < 8U) {
        uint8_t nibble = hex_char_to_nibble(*str);
        if (nibble == 0xFF) return false;
        val = (val << 4) | nibble;
        str++;
        count++;
    }

    if (count == 0) return false;
    *out = val;
    return true;
}

