static void diag_cmd_dump_memory(const char *args)
{
    uint32_t addr = 0;
    uint32_t size = 0;

    args = skip_whitespace(args);
    if (!parse_hex(args, &addr)) {
        diag_uart_send_string("Usage: dump_memory <hex_addr> <hex_size>\n");
        diag_uart_send_string("Example: dump_memory 0x20000000 0x40\n");
        diag_audit_log("dump_memory", false);
        return;
    }

    /* Find next argument */
    while (*args && *args != ' ' && *args != '\t') args++;
    args = skip_whitespace(args);

    if (!parse_hex(args, &size)) {
        size = 64U; /* Default 64 bytes */
    }

    /* Enforce maximum dump size */
    if (size > DIAG_MAX_DUMP_SIZE) {
        diag_uart_send_string("[LIMIT] Max dump size is ");
        diag_uart_send_decimal(DIAG_MAX_DUMP_SIZE);
        diag_uart_send_string(" bytes. Truncating.\n");
        size = DIAG_MAX_DUMP_SIZE;
    }

    /* Enforce alignment */
    addr &= ~0x3U;

    /* Security: check if region is allowed */
    if (!diag_is_region_allowed(addr, size)) {
        diag_audit_log("dump_memory", false);
        return;
    }

    diag_uart_send_string("\nMemory dump @ ");
    diag_uart_send_hex(addr);
    diag_uart_send_string(", ");
    diag_uart_send_decimal(size);
    diag_uart_send_string(" bytes:\n");
    diag_uart_send_string("--------------------------------------------\n");

    volatile uint8_t *ptr = (volatile uint8_t *)addr;
    for (uint32_t i = 0; i < size; i += 16U) {
        diag_uart_send_hex(addr + i);
        diag_uart_send_string(": ");

        /* Hex bytes */
        for (uint32_t j = 0; j < 16U && (i + j) < size; j++) {
            diag_uart_send_hex8(ptr[i + j]);
            diag_uart_send_char(' ');
            if (j == 7) diag_uart_send_char(' ');
        }

        /* Pad if less than 16 bytes */
        uint32_t remaining = size - i;
        if (remaining < 16U) {
            for (uint32_t j = remaining; j < 16U; j++) {
                diag_uart_send_string("   ");
                if (j == 7) diag_uart_send_char(' ');
            }
        }

        diag_uart_send_string(" |");
        /* ASCII representation */
        for (uint32_t j = 0; j < 16U && (i + j) < size; j++) {
            uint8_t c = ptr[i + j];
            if (c >= 0x20 && c <= 0x7E) {
                diag_uart_send_char((char)c);
            } else {
                diag_uart_send_char('.');
            }
        }
        diag_uart_send_string("|\n");
    }

    diag_uart_send_string("--------------------------------------------\n");
    diag_audit_log("dump_memory", true);
}

static void diag_cmd_read_flash(const char *args)
{
    uint32_t addr = 0;
    uint32_t size = 0;

    args = skip_whitespace(args);
    if (!parse_hex(args, &addr)) {
        diag_uart_send_string("Usage: read_flash <hex_addr> <hex_size>\n");
        diag_uart_send_string("Example: read_flash 0x08000000 0x80\n");
        diag_audit_log("read_flash", false);
        return;
    }

    while (*args && *args != ' ' && *args != '\t') args++;
    args = skip_whitespace(args);

    if (!parse_hex(args, &size)) {
        size = 64U;
    }

    /* Verify address is within flash range */
    if (addr < FLASH_BASE_ADDR || addr >= (FLASH_BASE_ADDR + FLASH_SIZE)) {
        diag_uart_send_string("[ERROR] Address outside flash region (");
        diag_uart_send_hex(FLASH_BASE_ADDR);
        diag_uart_send_string(" - ");
        diag_uart_send_hex(FLASH_BASE_ADDR + FLASH_SIZE);
        diag_uart_send_string(")\n");
        diag_audit_log("read_flash", false);
        return;
    }

    if (size > DIAG_MAX_DUMP_SIZE) {
        size = DIAG_MAX_DUMP_SIZE;
    }

    /* Delegate to dump_memory which handles access control */
    diag_uart_send_string("[Flash Read]\n");
    diag_cmd_dump_memory(args - (uint32_t)(args - skip_whitespace(args)));

    /* Rebuild args string for dump_memory - simpler to just call dump directly */
    char rebuilt[32];
    snprintf(rebuilt, sizeof(rebuilt), "0x%08lX 0x%lX", (unsigned long)addr, (unsigned long)size);
    diag_cmd_dump_memory(rebuilt);
}

